// ─── HEIC guard — browsers can't decode HEIC/HEIF (iPhone default format) ────
function isHeic(file) {
  if (!file) return false;
  const name = file.name || "";
  const ext = name.split(".").pop().toLowerCase();
  if (ext === "heic" || ext === "heif") return true;
  const type = (file.type || "").toLowerCase();
  if (type === "image/heic" || type === "image/heif") return true;
  return false;
}
function rejectHeic(file, e) {
  if (!isHeic(file)) return false;
  if (e && e.target) try { e.target.value = ""; } catch(_) {}
  alert("HEIC photos (iPhone default) can't be displayed in browsers.\n\nPlease convert to JPG first:\n- iPhone: open photo, share, Save as JPG\n- Mac: Preview > File > Export > JPEG\n- Windows: Photos app > Save a copy");
  return true;
}

// ─── Supabase Storage upload helper ──────────────────────────────────────────
// Uploads a File to the cabshoppro-files bucket and returns the public URL.
// Falls back to base64 data URL if upload fails (e.g. no bucket configured).
async function uploadImageToStorage(file, folder) {
  try {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) throw new Error("Not authenticated");
    const ext = (file.name.split(".").pop() || "jpg").toLowerCase();
    const path = `${user.id}/${folder}/${Date.now()}-${Math.random().toString(36).slice(2,7)}.${ext}`;
    const { error } = await supabase.storage
      .from("cabshoppro-files")
      .upload(path, file, { contentType: file.type, upsert: false });
    if (error) throw error;
    const { data: { publicUrl } } = supabase.storage
      .from("cabshoppro-files")
      .getPublicUrl(path);
    return { url: publicUrl, storagePath: path };
  } catch (err) {
    console.warn("Storage upload failed, falling back to base64:", err.message);
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = (ev) => resolve({ url: ev.target.result, storagePath: null });
      reader.readAsDataURL(file);
    });
  }
}

// ─── Phone number formatter ───────────────────────────────────────────────────
function fmtPhone(val) {
  const digits = val.replace(/\D/g, "").slice(0, 10);
  if (digits.length <= 3) return digits;
  if (digits.length <= 6) return `(${digits.slice(0,3)}) ${digits.slice(3)}`;
  return `(${digits.slice(0,3)}) ${digits.slice(3,6)}-${digits.slice(6)}`;
}

function useBreakpoint() {
  const [bp, setBp] = useState(() => {
    const w = window.innerWidth;
    return w < 640 ? "phone" : w < 1024 ? "tablet" : "desktop";
  });
  useEffect(() => {
    const fn = () => {
      const w = window.innerWidth;
      setBp(w < 640 ? "phone" : w < 1024 ? "tablet" : "desktop");
    };
    window.addEventListener("resize", fn);
    return () => window.removeEventListener("resize", fn);
  }, []);
  return bp;
}


// ─── Theme Hook ───────────────────────────────────────────────────────────────
function useTheme() {
  const [theme, setTheme] = useState(() => {
    return localStorage.getItem("cabshop-theme") || "dark";
  });

  useEffect(() => {
    document.documentElement.setAttribute("data-theme", theme);
    localStorage.setItem("cabshop-theme", theme);
  }, [theme]);

  const toggleTheme = () => setTheme(t => t === "dark" ? "light" : "dark");
  return { theme, toggleTheme };
}

