// ─── Helpers ──────────────────────────────────────────────────────────────────
var fmt = n => new Intl.NumberFormat("en-US",{style:"currency",currency:"USD",maximumFractionDigits:0}).format(n);

// ─── Voice Input Button ───────────────────────────────────────────────────────
function MicBtn({ onResult, style = {} }) {
  const { listening, start, stop, supported } = useVoice(onResult);
  if (!supported) return null;
  return (
    <button
      onMouseDown={start} onMouseUp={stop} onTouchStart={e=>{e.preventDefault();start();}} onTouchEnd={e=>{e.preventDefault();stop();}}
      title="Hold to dictate"
      className={listening ? "mic-pulse" : ""}
      style={{
        width:36, height:36, borderRadius:8, border:"none", flexShrink:0,
        background: listening ? "var(--accent3)" : "var(--surface3)",
        color: listening ? "#fff" : "var(--muted)",
        fontSize:16, display:"flex", alignItems:"center", justifyContent:"center",
        transition:"background 0.2s",
        ...style,
      }}
    >🎤</button>
  );
}

// ─── Voice-Enabled Input ──────────────────────────────────────────────────────
function Input({ label, value, onChange, type="text", placeholder="", style={}, options, voice=false }) {
  const base = {
    flex:1, padding:"10px 12px", borderRadius:8,
    background:"var(--surface2)", border:"1px solid var(--border)",
    color:"var(--text)", fontSize:15, outline:"none", transition:"border-color 0.2s",
    WebkitAppearance:"none",
  };
  const inner = type==="select" ? (
    <select value={value} onChange={onChange} style={{...base, cursor:"pointer", width:"100%"}} >
      {options?.map(o=><option key={o.value??o} value={o.value??o}>{o.label??o}</option>)}
    </select>
  ) : type==="textarea" ? (
    <textarea value={value} onChange={onChange} placeholder={placeholder} rows={3}
      style={{...base, resize:"vertical", width:"100%"}} />
  ) : (
    <input type={type} value={value} onChange={onChange} placeholder={placeholder} style={base}
      onFocus={e=>e.target.style.borderColor="var(--accent)"}
      onBlur={e=>e.target.style.borderColor="var(--border)"} />
  );

  return (
    <div style={{marginBottom:14,...style}}>
      {label && <div style={{fontSize:11,color:"var(--muted)",marginBottom:5,fontFamily:"var(--mono)",letterSpacing:"0.07em"}}>{label.toUpperCase()}</div>}
      {(voice && (type==="text"||type==="textarea")) ? (
        <div style={{display:"flex",gap:6,alignItems:"flex-start"}}>
          {inner}
          <MicBtn onResult={txt=>onChange({target:{value:(value?value+" ":"")+txt}})} style={{marginTop:0}} />
        </div>
      ) : inner}
    </div>
  );
}

// ─── Badge ────────────────────────────────────────────────────────────────────
function Badge({children,color="var(--accent)",style={}}) {
  return <span style={{display:"inline-flex",alignItems:"center",padding:"2px 10px",borderRadius:20,background:color+"22",color,border:`1px solid ${color}44`,fontSize:11,fontFamily:"var(--mono)",fontWeight:500,letterSpacing:"0.04em",whiteSpace:"nowrap",...style}}>{children}</span>;
}

// ─── Card ─────────────────────────────────────────────────────────────────────
function Card({children,style={},onClick}) {
  return (
    <div onClick={onClick} className="fadein" style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:14,padding:18,...style,cursor:onClick?"pointer":"default",transition:"border-color 0.2s,transform 0.15s,box-shadow 0.2s"}}
      onMouseEnter={e=>{if(onClick){e.currentTarget.style.borderColor="var(--accent)55";e.currentTarget.style.transform="translateY(-2px)";e.currentTarget.style.boxShadow="0 8px 32px rgba(0,0,0,0.3)";}}}
      onMouseLeave={e=>{e.currentTarget.style.borderColor="var(--border)";e.currentTarget.style.transform="none";e.currentTarget.style.boxShadow="none";}}>
      {children}
    </div>
  );
}

// ─── Modal ────────────────────────────────────────────────────────────────────
function Modal({title,children,onClose,wide=false}) {
  const bp = useBreakpoint();
  // Lock body scroll
  useEffect(()=>{document.body.style.overflow="hidden";return()=>{document.body.style.overflow="";};},[]);
  const isPhone = bp === "phone";
  return createPortal(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.78)",zIndex:1000,display:"flex",
        alignItems:isPhone?"flex-end":"center",
        justifyContent:"center",
        padding:isPhone?0:"20px"}}
      onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className="scalein" style={{background:"var(--surface)",border:"1px solid var(--border)",
          borderRadius:isPhone?"20px 20px 0 0":"16px",
          width:"100%",maxWidth:wide?760:540,
          maxHeight:isPhone?"92vh":"min(calc(100vh - 80px), 82vh)",
          overflowY:"auto",
          padding:"24px 22px 28px",
          margin:isPhone?0:"auto",
          display:"flex",flexDirection:"column"}}>
        {isPhone && <div style={{width:36,height:4,borderRadius:4,background:"var(--border)",margin:"0 auto 20px"}} />}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
          <div style={{fontSize:17,fontWeight:700}}>{title}</div>
          <button onClick={onClose} style={{background:"var(--surface2)",border:"none",color:"var(--muted)",borderRadius:8,width:34,height:34,fontSize:18}}>×</button>
        </div>
        {children}
      </div>
    </div>,
    document.body
  );
}

// ─── Button ───────────────────────────────────────────────────────────────────
function Btn({children,onClick,variant="primary",style={},small=false}) {
  const vs={
    primary:{background:"var(--accent)",color:"#000",border:"none"},
    secondary:{background:"var(--surface2)",color:"var(--text)",border:"1px solid var(--border)"},
    danger:{background:"var(--accent3)22",color:"var(--accent3)",border:"1px solid var(--accent3)44"},
    ghost:{background:"transparent",color:"var(--muted)",border:"none"},
    purple:{background:"var(--accent2)22",color:"var(--accent2)",border:"1px solid var(--accent2)44"},
  };
  return <button onClick={onClick} style={{padding:small?"6px 13px":"10px 20px",borderRadius:10,fontSize:small?12:14,fontWeight:600,minHeight:small?32:44,transition:"opacity 0.15s",...vs[variant],...style}}
    onMouseEnter={e=>e.currentTarget.style.opacity="0.82"} onMouseLeave={e=>e.currentTarget.style.opacity="1"}>{children}</button>;
}

// ─── Search Bar ───────────────────────────────────────────────────────────────
function SearchBar({value,onChange,placeholder="Search…"}) {
  const {listening,start,stop,supported} = useVoice(txt=>onChange({target:{value:txt}}));
  return (
    <div style={{position:"relative",flex:1,minWidth:0}}>
      <input value={value} onChange={onChange} placeholder={placeholder}
        style={{width:"100%",padding:"10px 40px 10px 36px",borderRadius:10,background:"var(--surface2)",border:"1px solid var(--border)",color:"var(--text)",fontSize:14,outline:"none"}} />
      <span style={{position:"absolute",left:11,top:"50%",transform:"translateY(-50%)",color:"var(--muted)",fontSize:16,pointerEvents:"none"}}>⌕</span>
      {supported && (
        <button onMouseDown={start} onMouseUp={stop} onTouchStart={e=>{e.preventDefault();start();}} onTouchEnd={e=>{e.preventDefault();stop();}}
          className={listening?"mic-pulse":""}
          style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",fontSize:16,color:listening?"var(--accent3)":"var(--muted)",padding:4}}>🎤</button>
      )}
    </div>
  );
}

